package com.google.gson.protobuf.generated;

import static org.mockito.Mockito.mock;
import static org.mockito.Mockito.verify;

import com.google.protobuf.ExtensionRegistry;
import com.google.protobuf.ExtensionRegistryLite;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class AnnotationsTest {

  private ExtensionRegistry extensionRegistryMock;
  private ExtensionRegistryLite extensionRegistryLiteMock;

  @BeforeEach
  public void setUp() {
    extensionRegistryMock = mock(ExtensionRegistry.class);
    extensionRegistryLiteMock = mock(ExtensionRegistryLite.class);
  }

  @Test
  public void testRegisterAllExtensions_withExtensionRegistry_invokesExtensionRegistryLite() {
    // Call the public registerAllExtensions(ExtensionRegistry) method
    Annotations.registerAllExtensions(extensionRegistryMock);

    // Verify that the cast to ExtensionRegistryLite and call happened
    // Since ExtensionRegistry extends ExtensionRegistryLite, the cast is valid
    // We cannot verify internal call directly, but no exception means successful call
  }

  @Test
  public void testRegisterAllExtensions_withExtensionRegistryLite() throws Exception {
    // Use reflection to invoke private registerAllExtensions(ExtensionRegistryLite)
    Method method = Annotations.class.getDeclaredMethod("registerAllExtensions", ExtensionRegistryLite.class);
    method.setAccessible(true);
    method.invoke(null, extensionRegistryLiteMock);

    // No exception means method executed; verify no interactions or side effects expected
  }
}
